import { defineAgent } from "eve";

export default defineAgent({
  model: "openai/gpt-5.4-mini",
});

import { connectSlackCredentials } from "@vercel/connect/eve";
import { slackChannel } from "eve/channels/slack";

// Replace the UID with your own Slack Connect client. See SETUP.md.
export default slackChannel({
  credentials: connectSlackCredentials("slack/approval-gate-starter"),
});

import { defineTool } from "eve/tools";
import { always } from "eve/tools/approval";
import { z } from "zod";

/**
 * Fake-dangerous action gated on human approval.
 * CUSTOMIZE HERE: replace the log with your real refund / ops call.
 */
export default defineTool({
  description:
    "Issue a refund for a charge. Always requires human approval in Slack before running.",
  inputSchema: z.object({
    chargeId: z.string().min(1),
    amountCents: z.number().int().positive(),
    reason: z.string().min(1).max(500),
  }),
  approval: always(),
  async execute({ chargeId, amountCents, reason }) {
    // Starter body: log only. Swap this for your payment provider call.
    console.log("[issue_refund] approved", {
      chargeId,
      amountCents,
      reason,
      at: new Date().toISOString(),
    });
    return {
      status: "logged",
      chargeId,
      amountCents,
      reason,
      note: "Starter stub — replace execute() with a real refund API call.",
    };
  },
});

import { defineTool } from "eve/tools";
import { once } from "eve/tools/approval";
import { z } from "zod";

/**
 * Contrast with issue_refund (always()): once() asks for approval on the
 * first call in a session, then auto-allows later calls of this tool.
 * CUSTOMIZE HERE: replace the log with a real restart / ops action.
 */
export default defineTool({
  description:
    "Restart a named service. Requires approval the first time in a session; later calls auto-allow.",
  inputSchema: z.object({
    service: z.string().min(1),
    reason: z.string().min(1).max(500),
  }),
  approval: once(),
  async execute({ service, reason }) {
    console.log("[restart_service] approved", {
      service,
      reason,
      at: new Date().toISOString(),
    });
    return {
      status: "logged",
      service,
      reason,
      note: "Starter stub — replace execute() with a real restart call.",
    };
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 1,
  timeoutMs: 120_000,
});

import { defineEval } from "eve/evals";

export default defineEval({
  description: "Issuing a refund parks on human approval instead of executing.",
  async test(t) {
    await t.send(
      "Issue a refund immediately for charge ch_demo_123 amounting to 2500 cents because the item never shipped."
    );
    t.parked();
    t.calledTool("issue_refund", { status: "pending", count: 1 });
  },
});

import { defineEval } from "eve/evals";

export default defineEval({
  description:
    "First restart_service call parks (once() still needs approval).",
  async test(t) {
    await t.send(
      "Restart the api service immediately because of a memory leak."
    );
    t.parked();
    t.calledTool("restart_service", { status: "pending", count: 1 });
  },
});
